import re

from .generic import apply_rules

DEFAULT_RULES = {
    re.compile(r"(?:芯褋褌懈|芯褋褌褜褞|芯褋褌械泄|芯褋褌褟屑|芯褋褌褟屑懈|芯褋褌褟褏)$"): "芯褋褌褜",
    re.compile(r"(?:褋褌胁邪|褋褌胁|褋褌胁褍|褋褌胁邪屑|褋褌胁芯屑|褋褌胁邪屑懈|褋褌胁械|褋褌胁邪褏)$"): "褋褌胁芯",
}


def apply_ru(token: str) -> str | None:
    "Apply pre-defined rules for Russian."
    if token.endswith("褢"):
        return token.replace("褢", "械")

    if len(token) < 10 or token[0].isupper() or "-" in token:
        return None

    # token = token.replace("邪虂", "a")
    # token = token.replace("芯虂", "o")
    # token = token.replace("懈虂", "懈")
    # if RUSSIAN_ENDINGS_OCTB.search(token):
    #     return RUSSIAN_ENDINGS_OCTB.sub("芯褋褌褜", token)
    # if RUSSIAN_ENDINGS_CTBO.search(token):
    #     return RUSSIAN_ENDINGS_CTBO.sub("褋褌胁芯", token)

    return apply_rules(token, DEFAULT_RULES)
